(1, 'Straight Ankle Lock',    'SUBMISSION', 'Llave de tobillo recta: pie en la axila, caderas extendidas. Legal en todos los cinturones.',                                                   'WHITE',  'BOTH', (SELECT id FROM position WHERE name='Single Leg X'               AND owner_id=1), (SELECT id FROM position WHERE name='Submitted' AND owner_id=1), 'PUBLIC', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, 0),
(1, 'Inside Heel Hook',       'SUBMISSION', 'Torsión del talón hacia adentro atacando el ligamento externo de la rodilla. Legal desde brown belt IBJJF.',                                    'BROWN',  'NOGI', (SELECT id FROM position WHERE name='Single Leg X'               AND owner_id=1), (SELECT id FROM position WHERE name='Submitted' AND owner_id=1), 'PUBLIC', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, 0),
(1, 'Outside Heel Hook',      'SUBMISSION', 'Torsión del talón hacia afuera. Ataca ligamentos internos de rodilla. El más peligroso de los leg locks.',                                      'BROWN',  'NOGI', (SELECT id FROM position WHERE name='Outside Heel Hook Position' AND owner_id=1), (SELECT id FROM position WHERE name='Submitted' AND owner_id=1), 'PUBLIC', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, 0),
(1, 'Kneebar',                'SUBMISSION', 'Hiperextensión de la rodilla aislando la pierna entre el cuerpo. Ataque desde leg entanglement o mount.',                                       'PURPLE', 'BOTH', (SELECT id FROM position WHERE name='Leg Entanglement'           AND owner_id=1), (SELECT id FROM position WHERE name='Submitted' AND owner_id=1), 'PUBLIC', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, 0),
(1, 'Toe Hold',               'SUBMISSION', 'Figura de 4 en el pie torciendo el tobillo/rodilla. Muy versátil desde cualquier leg entanglement.',                                            'PURPLE', 'BOTH', (SELECT id FROM position WHERE name='Leg Entanglement'           AND owner_id=1), (SELECT id FROM position WHERE name='Submitted' AND owner_id=1), 'PUBLIC', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, 0),
(1, 'Calf Slicer',            'SUBMISSION', 'Compresión de gemelo: espinilla o antebrazo detrás de la rodilla doblando la pierna. Ilegal hasta purple belt.',                               'PURPLE', 'BOTH', (SELECT id FROM position WHERE name='Leg Entanglement'           AND owner_id=1), (SELECT id FROM position WHERE name='Submitted' AND owner_id=1), 'PUBLIC', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, 0),
